import{_ as l,o as i,c as o,a2 as a}from"./chunks/framework.VshInwhI.js";const m=JSON.parse('{"title":"Vue 代码规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/01-vue-code.md","filePath":"mango-pmo/rules/frontend/01-vue-code.md"}'),d={name:"mango-pmo/rules/frontend/01-vue-code.md"};function c(r,e,t,n,u,s){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="vue-代码规范" tabindex="-1">Vue 代码规范 <a class="header-anchor" href="#vue-代码规范" aria-label="Permalink to &quot;Vue 代码规范&quot;">​</a></h1><h2 id="_1-基本规则" tabindex="-1">1. 基本规则 <a class="header-anchor" href="#_1-基本规则" aria-label="Permalink to &quot;1. 基本规则&quot;">​</a></h2><ul><li>使用 Vue 3。</li><li>使用 <code>script setup</code>。</li><li>使用 TypeScript。</li><li>不使用 <code>any</code>。</li><li>新增页面和组件优先复用现有能力。</li></ul><h2 id="_2-组件规则" tabindex="-1">2. 组件规则 <a class="header-anchor" href="#_2-组件规则" aria-label="Permalink to &quot;2. 组件规则&quot;">​</a></h2><ul><li>组件名使用 <code>PascalCase</code>。</li><li>页面组件放 <code>views</code>。</li><li>只在当前页面使用的组件放页面目录。</li><li>可跨模块复用的组件放对应 <code>packages/*</code>。</li><li>不在 <code>apps</code> 和 <code>packages</code> 里维护两份相同组件。</li></ul><h2 id="_3-组件使用规则" tabindex="-1">3. 组件使用规则 <a class="header-anchor" href="#_3-组件使用规则" aria-label="Permalink to &quot;3. 组件使用规则&quot;">​</a></h2><ul><li>优先直接使用 Element Plus 原生组件。</li><li>只有存在稳定复用价值时才封装组件。</li><li>公共组件禁止直接依赖基座 store、router、菜单、启动逻辑。</li><li>公共组件需要的数据和行为通过 <code>props</code>、<code>emits</code>、回调传入。</li></ul><h2 id="_3-1-页面布局规则" tabindex="-1">3.1 页面布局规则 <a class="header-anchor" href="#_3-1-页面布局规则" aria-label="Permalink to &quot;3.1 页面布局规则&quot;">​</a></h2><ul><li>页面布局必须优先使用 Element Plus 官方标准布局和组件用法，参考 <code>https://element-plus.org/zh-CN/</code>。</li><li>栅格布局使用 <code>el-row</code>、<code>el-col</code> 和 24 分栏体系；需要间距、对齐或响应式时使用 <code>gutter</code>、<code>justify</code>、<code>align</code>、<code>xs/sm/md/lg/xl</code> 等标准属性。</li><li>表单页面使用 <code>el-form</code>、<code>el-form-item</code>、<code>label-width</code>、<code>el-row</code>、<code>el-col</code> 组织字段；禁止用零散 <code>div</code> 拼接表单布局。</li><li>列表、详情、弹窗、抽屉等后台页面优先使用 Element Plus 的 <code>el-table</code>、<code>el-descriptions</code>、<code>el-dialog</code>、<code>el-drawer</code>、<code>el-card</code> 等标准结构。</li><li>禁止在业务页面自创非标准布局体系、随意嵌套卡片、用大段临时 CSS 修正本可由 Element Plus 标准布局解决的问题。</li></ul><h2 id="_3-2-组件示例规则" tabindex="-1">3.2 组件示例规则 <a class="header-anchor" href="#_3-2-组件示例规则" aria-label="Permalink to &quot;3.2 组件示例规则&quot;">​</a></h2><ul><li>组件库示例页必须使用 Element Plus 文档风格。</li><li>每个常见用法都必须是独立示例，示例下方提供可展开/收起的代码。</li><li>示例覆盖基础用法、常用变体、禁用/只读、业务集成和边界场景。</li><li>示例页底部必须提供属性、slot、方法/事件、对象字段或接口返回字段明细。</li><li>示例文案只说明真实用法和约束，不写与组件无关的营销描述。</li><li>同一类能力优先由一个组件通过 <code>props</code>、<code>slots</code>、<code>events</code> 支撑，禁止为了展示多个场景拆出多个前端组件作为长期实现。</li></ul><h2 id="_4-类型规则" tabindex="-1">4. 类型规则 <a class="header-anchor" href="#_4-类型规则" aria-label="Permalink to &quot;4. 类型规则&quot;">​</a></h2><ul><li>对象结构优先使用明确类型。</li><li>API 类型与页面状态类型分开定义。</li><li>公共类型放公共位置。</li><li>页面私有类型不要放到公共包。</li><li>后端 <code>Long</code>、雪花 ID、数据库主键、业务主键等标识字段在前端统一使用字符串语义，公共类型使用 <code>ApiId</code>。</li><li>禁止对 ID 调用 <code>Number(id)</code>、<code>parseInt(id)</code> 后再用于接口请求、路由参数、表格 key、组件 model 或文件 token。</li><li>只有页码、数量、金额、排序等真实数值字段可以建模为 <code>number</code>。</li></ul><h2 id="_4-1-文件上传与回显规则" tabindex="-1">4.1 文件上传与回显规则 <a class="header-anchor" href="#_4-1-文件上传与回显规则" aria-label="Permalink to &quot;4.1 文件上传与回显规则&quot;">​</a></h2><ul><li>业务表单提交给业务 API 时，只能提交文件中心标识，例如 <code>fileId</code>、<code>fileIds</code>、<code>attachmentIds</code>、<code>mango-file:{id}</code> token。</li><li>上传组件返回的 <code>url</code>、<code>previewUrl</code>、<code>downloadUrl</code>、<code>directPreviewUrl</code>、<code>directDownloadUrl</code> 只允许用于当前页面即时展示，禁止写入业务表单 payload。</li><li>业务页面回显图片、附件、图标时，应按文件 ID 通过 <code>@mango/file</code> 或 <code>mango-file</code> API 获取临时预览/下载地址。</li><li>禁止把 MinIO/S3/OSS/COS/Kodo 直连地址、预签名 URL、文件服务下载 URL 存入业务字段、前端缓存或配置 JSON 作为长期数据。</li></ul><h2 id="_4-2-真实数据规则" tabindex="-1">4.2 真实数据规则 <a class="header-anchor" href="#_4-2-真实数据规则" aria-label="Permalink to &quot;4.2 真实数据规则&quot;">​</a></h2><ul><li>页面数据必须来自真实 API、配置、字典服务、枚举契约或可替换 provider。</li><li>字典、枚举、菜单、权限、租户默认数据、状态映射和业务配置不得在页面中写成最终静态数据。</li><li>Mock 只能用于本地开发或测试，不能作为交付完成依据。</li><li>后端接口已具备能力时，前端必须列出 mock 替换清单并完成真实联调。</li><li>页面交付必须验证新增、编辑、搜索、回显、空结果、接口错误和权限不足场景。</li></ul><h2 id="_5-样式规则" tabindex="-1">5. 样式规则 <a class="header-anchor" href="#_5-样式规则" aria-label="Permalink to &quot;5. 样式规则&quot;">​</a></h2><ul><li>优先使用现有设计变量和主题变量。</li><li>不直接覆盖 Element Plus 全局样式。</li><li>不为一个页面临时定义新的全局设计规则。</li><li>第三方组件样式必须显式引入。</li></ul><h2 id="_6-store-规则" tabindex="-1">6. Store 规则 <a class="header-anchor" href="#_6-store-规则" aria-label="Permalink to &quot;6. Store 规则&quot;">​</a></h2><ul><li>基座 store 只服务基座。</li><li>公共包禁止直接依赖基座 store。</li><li>跨包状态通过契约、参数、事件传递。</li></ul><h2 id="_7-路由规则" tabindex="-1">7. 路由规则 <a class="header-anchor" href="#_7-路由规则" aria-label="Permalink to &quot;7. 路由规则&quot;">​</a></h2><ul><li>路由按模块组织。</li><li>动态路由逻辑集中管理。</li><li>页面组件不直接写权限装配逻辑。</li></ul><h2 id="_8-禁止事项" tabindex="-1">8. 禁止事项 <a class="header-anchor" href="#_8-禁止事项" aria-label="Permalink to &quot;8. 禁止事项&quot;">​</a></h2><ul><li>为简单按钮、输入框做无意义二次封装</li><li>在公共组件里引用基座代码</li><li>同一能力在多个目录重复实现</li><li>直接把页面临时样式扩散成全局规则</li><li>提交临时代码、止血代码、绕过式兼容代码作为最终实现</li><li>为了规避构建或运行错误，给 import、类型、接口参数增加没有架构含义的特殊写法</li><li>在没有定位根因和完成验证前，把“能跑起来”的改动交付</li><li>业务表单把文件访问地址当作业务数据提交</li><li>用页面静态数组、mock 数据或硬编码状态替代真实 API、配置、字典服务或枚举契约</li></ul><h2 id="_9-临时代码处理规则" tabindex="-1">9. 临时代码处理规则 <a class="header-anchor" href="#_9-临时代码处理规则" aria-label="Permalink to &quot;9. 临时代码处理规则&quot;">​</a></h2><ul><li>临时代码只能用于本地定位问题，提交前必须删除或重构为正式方案。</li><li>正式方案必须说明能力归属、依赖方向和复用边界。</li><li>单体和微前端共用的菜单、权限、图标、运行时能力必须沉淀到 <code>packages/*</code>，禁止通过 app 私有文件互相中转。</li><li>对运行态问题的修复必须同时验证开发态和生产构建态。</li><li>如果确实需要过渡兼容，必须有明确删除条件、关联任务和注释说明，不允许无期限保留。</li></ul>',27)])])}const _=l(d,[["render",c]]);export{m as __pageData,_ as default};
